import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"语音技能设计规范","description":"","frontmatter":{"title":"语音技能设计规范"},"headers":[],"relativePath":"custom-biz/skill-studio/voice-design-guide.md","filePath":"custom-biz/skill-studio/voice-design-guide.md","lastUpdated":null}'),o={name:"custom-biz/skill-studio/voice-design-guide.md"};function r(u,l,h,p,d,n){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="目-录" tabindex="-1">目 录 <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;目 录&quot;">​</a></h1><ol><li>技能场景定义 1.1 定义技能</li><li>语料设计 2.1 简洁直白，亲切友好 2.2 丰富多变，应变能力强 2.3 以服务用户的核心意图为前提 2.4 清晰地给出选择 2.5 回应要为用户的 “耳朵” 服务 2.6 兜底语料 2.7 考虑用户关闭数据获取的情况</li><li>多轮对话设计 3.1 首先列出最短的对话路径 3.2 将备选路径和决策树列举出来 3.3 概括出系统逻辑 3.4 对话中加入引导语 3.5 汇总选择 3.6 处理潜在需求 3.7 精细化拆分 3.8 无响应时主动反馈</li><li>发布技能 4.1 确保服务稳定可靠 4.2 技能信息有标识度 4.3 技能描述简洁易懂</li></ol><h2 id="技能场景定义" tabindex="-1">技能场景定义 <a class="header-anchor" href="#技能场景定义" aria-label="Permalink to &quot;技能场景定义&quot;">​</a></h2><p>首先定义技能的<strong>应用场景</strong>，避免一个技能完成多个功能。</p><h3 id="定义技能" tabindex="-1">定义技能 <a class="header-anchor" href="#定义技能" aria-label="Permalink to &quot;定义技能&quot;">​</a></h3><p>定义技能的几个问题：</p><ol><li>这个技能能做什么？为什么用户需要这个技能?</li><li>用户在使用这个技能之前、当时、之后，会干什么？</li><li>在这个技能中，有什么是用户不使用这个技能或使用别的技能得不到的？</li><li>有什么信息是用户希望得到的？</li><li>用户通过说/做什么能唤醒这个技能？</li><li>哪一个功能点能直接支持这个技能？</li><li>技能提供的信息是否需要从别的网页或应用中调用？</li></ol><h2 id="语料设计" tabindex="-1">语料设计 <a class="header-anchor" href="#语料设计" aria-label="Permalink to &quot;语料设计&quot;">​</a></h2><p>语料指用户发出指令后技能做出回应的话术，尽可能多地考虑用户和技能之间的对话的发展。好的语料应该：</p><h3 id="简洁直白-亲切友好" tabindex="-1">简洁直白，亲切友好 <a class="header-anchor" href="#简洁直白-亲切友好" aria-label="Permalink to &quot;简洁直白，亲切友好&quot;">​</a></h3><ol><li>使用简洁、口语化语言。 正确示范</li></ol><ul><li>用户：订今晚去北京的机票。</li><li>技能：今晚飞北京已经没有票了，要不要改坐高铁呢？</li></ul><p>错误示范</p><ul><li>用户：订今晚去北京的机票。</li><li>技能：今晚去往北京的机票已无剩余，无法购买，可否改乘高铁？</li></ul><ol start="2"><li>语料兼备幽默、风趣、委婉、温柔、俏皮的多重风格转换，增加生动活泼力。</li></ol><p>正确示范</p><ul><li>用户：你最喜欢的人是谁</li><li>技能：欲把相思说似谁，当然是你呀~</li></ul><p>错误示范</p><ul><li>用户：你最喜欢的人是谁？</li><li>技能：没什么喜欢的</li></ul><ol start="3"><li>尽可能避免使用歉意词。</li></ol><p>正确示范</p><ul><li>用户：打电话给爸爸</li><li>技能：通讯录中没有找到“爸爸”呢。</li></ul><p>错误示范</p><ul><li>用户：打电话给爸爸。</li><li>技能：对不起，通讯录中没有找到“爸爸”。</li></ul><ol start="4"><li>回应简洁，避免重复。 正确示范</li></ol><ul><li>用户：帮我找手机。</li><li>技能：好的，请说一下你的电话号码哦。</li></ul><p>错误示范</p><ul><li>用户：帮我找手机。</li><li>技能：感谢使用找手机技能，本技能可以通过拨打你的电话找到你的手机。现在说出你的手机号码，帮你拨打哦。</li></ul><ol start="5"><li>尽可能只回复重点，省略无关消息。 正确示范</li></ol><ul><li>用户：今天要带伞吗？</li><li>技能：今天北京雷阵雨，需要带伞哦。</li></ul><p>错误示范</p><ul><li>用户：今天要带伞吗？</li><li>技能：今天北京雷阵雨，气温15~21度，空气湿度80%，记得要带伞哦。</li></ul><ol start="6"><li>避免无意义交互。 正确示范</li></ol><ul><li>用户：给我讲个笑话吧。</li><li>技能：（随机讲笑话）</li></ul><p>错误示范</p><ul><li>用户：给我讲个笑话吧。</li><li>技能：你是要听笑话对吗？</li></ul><ol start="7"><li>避免要求用户用特定的方式表达意图。 正确示范</li></ol><ul><li>用户：明晚八点有个饭局。</li><li>技能：需要我帮你设置一个明晚八点的提醒吗？</li></ul><p>错误示范</p><ul><li>用户：明晚八点有个饭局。</li><li>技能：如果你想设置提醒，请对我说：提醒我明晚八点有个饭局。</li></ul><h3 id="丰富多变-应变能力强" tabindex="-1">丰富多变，应变能力强 <a class="header-anchor" href="#丰富多变-应变能力强" aria-label="Permalink to &quot;丰富多变，应变能力强&quot;">​</a></h3><ol><li>答复多样化。</li></ol><p>举例</p><ul><li>用户：红烧肉怎么做？</li><li>技能回复1：鱼香肉丝是道不错的美味呦，做法是这样的：…</li><li>技能回复2：做菜我最拿手哦，红烧肉的步骤是：…</li><li>技能回复3：帮你找到啦：…</li></ul><h3 id="以服务用户的核心意图为前提" tabindex="-1">以服务用户的核心意图为前提 <a class="header-anchor" href="#以服务用户的核心意图为前提" aria-label="Permalink to &quot;以服务用户的核心意图为前提&quot;">​</a></h3><p>技能应优先回复用户的核心意图。当无法满足用户需求时，应表达清楚技能的状态，以免用户困惑。</p><p>正确示范</p><ul><li>用户：我想看新浪财经频道。</li><li>（没有新浪财经频道的信源，但找到爱奇艺财经频道）</li><li>技能：没有找到新浪财经频道，可以看看爱奇艺财经频道。</li></ul><p>错误示范</p><ul><li>用户：我想看新浪财经频道。</li><li>（没有新浪财经频道的信源，但找到爱奇艺财经频道）</li><li>技能：为你找到爱奇艺财经频道。</li></ul><h3 id="清晰地给出选择" tabindex="-1">清晰地给出选择 <a class="header-anchor" href="#清晰地给出选择" aria-label="Permalink to &quot;清晰地给出选择&quot;">​</a></h3><p>在为用户提供选择的时候，要组织好语言，明确这是一个从几个选择里挑一个的问题，而不是“是与否”、“要或不要”的问题。</p><p>正确示范</p><ul><li>用户：帮我定杯拿铁。</li><li>技能：你是想要中杯还是大杯呢？</li><li>用户：大杯。</li></ul><p>错误示范</p><ul><li>用户：帮我定杯拿铁。</li><li>技能：你是要中杯或者大杯吗？</li><li>用户：是的。</li></ul><h3 id="回应要为用户的-耳朵-服务" tabindex="-1">回应要为用户的 “耳朵” 服务 <a class="header-anchor" href="#回应要为用户的-耳朵-服务" aria-label="Permalink to &quot;回应要为用户的 “耳朵” 服务&quot;">​</a></h3><p>以应用技能的设备没有屏幕，或者用户不会 “看” 信息为前提，让技能的回复能通过 “听” 就能很容易地理解。</p><p>正确示范</p><ul><li>用户：火箭队和魔术现在比赛情况怎样？</li><li>技能：火箭队目前得分66，魔术队目前得分54，比赛进行到第三场。</li></ul><p>错误示范</p><ul><li>用户：火箭队和魔术现在比赛情况怎样？</li><li>技能：火箭（65-17-1）66，魔术（25-57-0）54，第三场，剩余时间 5:24。</li></ul><h3 id="兜底语料" tabindex="-1">兜底语料 <a class="header-anchor" href="#兜底语料" aria-label="Permalink to &quot;兜底语料&quot;">​</a></h3><p>问题超出信源库范围时，生动的兜底语料提高用户体验。</p><p>正确示范</p><ul><li>用户：红烧肉怎么做？</li><li>技能回复1：我突然想不起来了，问我别的菜呗。</li><li>技能回复2：脑袋空空，咱们换个菜吧。</li></ul><p>错误示范</p><ul><li>用户：红烧肉怎么做？</li><li>技能：我没听清，能再说一遍吗？</li></ul><h3 id="考虑用户关闭数据获取的情况" tabindex="-1">考虑用户关闭数据获取的情况 <a class="header-anchor" href="#考虑用户关闭数据获取的情况" aria-label="Permalink to &quot;考虑用户关闭数据获取的情况&quot;">​</a></h3><p>正确示范</p><ul><li>用户：今天天气怎样？</li><li>技能：请问你现在在哪个城市？</li><li>用户：我在北京。</li><li>技能：今天北京天气晴朗，气温为15~21度。</li></ul><p>错误示范</p><ul><li>用户：今天天气怎样？</li><li>技能：你还没授权定位数据，无法使用天气查询哦。</li></ul><h2 id="多轮对话设计" tabindex="-1">多轮对话设计 <a class="header-anchor" href="#多轮对话设计" aria-label="Permalink to &quot;多轮对话设计&quot;">​</a></h2><p>基础的语料设计可能不能满足用户与技能的实际互动需求。用户可能会说得太少，也可能说得太多，还可能词不达意，说很多开发者预料不到的东西。运用以下技巧，开发者可以扩展语料库，用多轮对话的形式更好地捕获用户在对话中给出的重要信息。</p><h3 id="首先列出最短的对话路径" tabindex="-1">首先列出最短的对话路径 <a class="header-anchor" href="#首先列出最短的对话路径" aria-label="Permalink to &quot;首先列出最短的对话路径&quot;">​</a></h3><p>最短的对话路径通常是用户一次性提供所有有用信息的对话。</p><h3 id="将备选路径和决策树列举出来" tabindex="-1">将备选路径和决策树列举出来 <a class="header-anchor" href="#将备选路径和决策树列举出来" aria-label="Permalink to &quot;将备选路径和决策树列举出来&quot;">​</a></h3><p>如果用户所说的没有将所有必需的信息给出，可以在流程中确定备选路径。</p><h3 id="概括出系统逻辑" tabindex="-1">概括出系统逻辑 <a class="header-anchor" href="#概括出系统逻辑" aria-label="Permalink to &quot;概括出系统逻辑&quot;">​</a></h3><p>识别系统决策，如这是一个新用户还是一个老用户。检查用户遵循的流程可能可以改善用户体验。</p><h3 id="对话中加入引导语" tabindex="-1">对话中加入引导语 <a class="header-anchor" href="#对话中加入引导语" aria-label="Permalink to &quot;对话中加入引导语&quot;">​</a></h3><p>不要假设用户知道接下来该做什么或将要发生什么。多轮对话中可以加入友好的引导语，让用户清晰地知道接下来该怎样与技能进行交流。如：</p><ol><li>提示用户何时需要提供更多信息。</li><li>一次只要求一个信息。</li><li>给用户提供选择，但尽量不要给出三个以上的选项。</li><li>向用户确认他的选择和重要信息。</li><li>传达多个信息时应通过“第一步”、“然后”、“最后”等序列词便于用户理解。</li></ol><h3 id="汇总选择" tabindex="-1">汇总选择 <a class="header-anchor" href="#汇总选择" aria-label="Permalink to &quot;汇总选择&quot;">​</a></h3><p>进行多论对话后，应向用户确认各轮回答的信息并反馈给用户。</p><p>正确示范</p><ul><li>用户：帮我订今天去北京的机票。</li><li>技能：好的，请说出发地点。</li><li>用户：广州</li><li>技能：好的请说起飞时间段。</li><li>用户：中午十二点之后。</li><li>技能：好的，你需要订X月X日，中午十二点后，从广州飞往北京的航班对吗？</li><li>用户：是的。</li><li>技能：好的，为你找到…</li></ul><p>错误示范</p><ul><li>用户：帮我订今天去北京的机票.</li><li>技能：好的，请说出发地点。</li><li>用户：广州。</li><li>技能：好的，请说起飞时间段。</li><li>用户：中午十二点之后。</li><li>技能：好的，为你找到….</li></ul><h3 id="处理潜在需求" tabindex="-1">处理潜在需求 <a class="header-anchor" href="#处理潜在需求" aria-label="Permalink to &quot;处理潜在需求&quot;">​</a></h3><p>多为用户考虑场景中潜在的需求，并尽可能周全地满足。例如：当介绍复杂的规则时，可以为用户考虑没听清或没听懂的情况，提供再听一遍的选项。也可以为已经了解规则的用户提供跳过的选项。</p><h3 id="精细化拆分" tabindex="-1">精细化拆分 <a class="header-anchor" href="#精细化拆分" aria-label="Permalink to &quot;精细化拆分&quot;">​</a></h3><p>某个场景下的各种交互情况均需进行考虑，作精细化拆分，针对各种情况，需要提供针对性更强的回答，要求符合语境及交互感。</p><p>正确示范</p><ul><li>用户：成语接龙</li><li>技能：已为你打开成语接龙，你可以选择你先开始或者我先开始，不想玩了请对我说“退出”。</li><li>用户：你先开始。</li><li>技能：好的，那我先来咯~ 和风细雨。</li><li>用户：雨过天晴。</li><li>技能：真棒，回答正确，再接再厉。下一个，雨过天晴。</li><li>用户：熠熠生辉。</li><li>技能：你的回答不正确哦，再试一次吧~</li><li>用户：提示一下吧</li><li>技能：好的，雨过天晴可以接晴天霹雳。</li><li>用户：换一个吧</li><li>技能：如果你想重开一局，可以对我说“重来”。</li></ul><p>错误示范</p><ul><li>用户：打开成语接龙</li><li>技能：和风细雨</li><li>用户：雨过天晴</li><li>技能：晴天霹雳</li><li>用户：熠熠生辉</li><li>技能：你的回答不对哦，再试一次~</li><li>用户：提示一下吧</li><li>技能：我好像没听懂…</li><li>用户：换一个吧</li><li>技能：我好像没听懂…</li></ul><h3 id="无响应时主动反馈" tabindex="-1">无响应时主动反馈 <a class="header-anchor" href="#无响应时主动反馈" aria-label="Permalink to &quot;无响应时主动反馈&quot;">​</a></h3><p>当用户连续多次没有命中意图时，在告知没有理解并且作出更清晰的引导同时，需要明确告知用户应该怎样退出技能或主动为用户退出当前技能。</p><p>尽可能用“鼓励”的方式引导用户更正“错误”，主动询问用户意图，引导用户完成目标，而不是轻易终结对话。</p><p>正确示范</p><ul><li>用户：我想查天气。</li><li>技能：请问要查哪个城市的天气呢？</li><li>用户：天气热要多喝水。</li><li>技能：这个没听清呢，请你说出要查天气的城市名哦。</li></ul><p>错误示范</p><ul><li>用户：我想查天气。</li><li>技能：请问要查哪个城市的天气呢？</li><li>用户：天气热要多喝水。</li><li>技能：这个没听懂，自动为你退出技能。</li></ul><h2 id="发布技能" tabindex="-1">发布技能 <a class="header-anchor" href="#发布技能" aria-label="Permalink to &quot;发布技能&quot;">​</a></h2><h3 id="确保服务稳定可靠" tabindex="-1">确保服务稳定可靠 <a class="header-anchor" href="#确保服务稳定可靠" aria-label="Permalink to &quot;确保服务稳定可靠&quot;">​</a></h3><p>应该严格保证技能的后端服务稳定可靠，快速响应用户请求，达到用户良好的使用预期。</p><h3 id="技能信息有标识度" tabindex="-1">技能信息有标识度 <a class="header-anchor" href="#技能信息有标识度" aria-label="Permalink to &quot;技能信息有标识度&quot;">​</a></h3><p>通过定义独立且有差异化的技能功能，选用不易混淆的名称来命名你的技能，给用户一个清晰的印象，让你的技能脱颖而出。</p><h3 id="技能描述简洁易懂" tabindex="-1">技能描述简洁易懂 <a class="header-anchor" href="#技能描述简洁易懂" aria-label="Permalink to &quot;技能描述简洁易懂&quot;">​</a></h3><p>尽可能完善技能的描述信息，具体要求可参照<a href="/custom-biz/skill-studio/review-guide.html">技能审核规范</a>。</p>',112)])])}const b=i(o,[["render",r]]);export{c as __pageData,b as default};
